# compute best matches in quran DB using token F1 and LCS ratio
def token_f1(a, b):
    # a and b are normalized strings
    a_tokens = a.split()
    b_tokens = b.split()
    if not a_tokens or not b_tokens:
        return 0.0
    a_set = {}
    for t in a_tokens:
        a_set[t] = a_set.get(t,0)+1
    b_set = {}
    for t in b_tokens:
        b_set[t] = b_set.get(t,0)+1
    # overlap count
    overlap = 0
    for t, cnt in a_set.items():
        if t in b_set:
            overlap += min(cnt, b_set[t])
    prec = overlap / len(a_tokens)
    rec = overlap / len(b_tokens)
    if prec+rec == 0:
        return 0.0
    return 2*prec*rec/(prec+rec)

def lcs_ratio(a, b):
    # compute longest common substring length ratio relative to b (span)
    # use dynamic programming; strings a and b are normalized without spaces maybe keep spaces
    A = a
    B = b
    n = len(A)
    m = len(B)
    # dynamic programming for longest common substring
    dp = [[0]*(m+1) for _ in range(n+1)]
    longest = 0
    for i in range(n):
        for j in range(m):
            if A[i] == B[j]:
                dp[i+1][j+1] = dp[i][j] + 1
                if dp[i+1][j+1] > longest:
                    longest = dp[i+1][j+1]
    if m == 0:
        return 0.0
    return longest / m

